// Tests for DockerRuntime that exercise the actual Docker daemon via
// dockerode. Lives in the regular test suite (not split out as
// "integration") so Stryker mutation testing sees these assertions —
// without that, every Docker code path in src/runner/runtime.ts would
// show as no-coverage.
//
// Skipped automatically on machines without a reachable Docker socket
// (CI without Docker, dev box with Desktop stopped) via a sync
// `docker version --format` probe at module load. `pnpm test` is safe
// to run anywhere; the suite either passes or skips, never errors.
//
// Coverage:
// - DockerImageArtifact pull-policy semantics (always, if-missing, never)
// - DockerBuildArtifact end-to-end (tar context → image → container)
// - Container lifecycle: prepare creates a container; stop kills + removes it
// - Auto-tagged image cleanup on build failure (P0-2 contract)
// - User-supplied imageTag preserved on build failure

import { afterAll, beforeAll, describe, expect } from "vitest";
import { Data, Effect } from "effect";
import Docker from "dockerode";
import { execSync } from "node:child_process";
import { existsSync, mkdirSync, mkdtempSync, writeFileSync } from "node:fs";
import * as os from "node:os";
import * as path from "node:path";
import { DockerRuntime, type RuntimeHandle } from "../src/runner/index.js";
import {
  AgentId,
  ProjectId,
  ScenarioId,
  type AgentDeclaration,
  type RunPlan,
} from "../src/core/types.js";
import { itEffect, expectLeft, EITHER_LEFT } from "./support/effect.js";

// Tagged error for upstream Promise wrappers used in this test file —
// keeps the Effect channel typed (no generic Error in the lint-checked
// surface) while letting test assertions surface dockerode rejections
// with their original message.
class IntegrationDockerError extends Data.TaggedError("IntegrationDockerError")<{
  readonly message: string;
}> {}

// Boundary helper that adapts dockerode's Promise-returning API into a
// typed Effect. The lint rule against Promise<> return types targets
// application code; here the Promise comes from upstream and is the
// natural shape to pass through.
// eslint-disable-next-line agent-code-guard/promise-type
function awaitDocker<A>(thunk: () => Promise<A>): Effect.Effect<A, IntegrationDockerError, never> {
  return Effect.tryPromise({
    try: thunk,
    catch: (err) => new IntegrationDockerError({
      message: err instanceof Error ? err.message : String(err),
    }),
  });
}

const TEST_IMAGE = "alpine:3.19";

// Probe the Docker daemon synchronously at module load. The
// `--format {{.Server.Version}}` invocation exits non-zero when the
// daemon is unreachable (plain `docker info` / `docker version` exit 0
// on macOS even when the socket is down — they only report the
// client). describe.skipIf evaluates at registration time, so the
// probe must be sync.
const dockerAvailable: boolean = (() => {
  try {
    execSync("docker version --format {{.Server.Version}}", {
      stdio: "ignore",
      timeout: 5_000,
    });
    return true;
  } catch (err) {
    void err;
    return false;
  }
})();

let pullErrorMessage: string | null = null;

// vitest hook signatures require async — the agent-code-guard
// async-keyword rule is opinionated about *application* code, not
// test fixtures that wrap upstream Promise APIs.
// eslint-disable-next-line agent-code-guard/async-keyword
beforeAll(async () => {
  if (!dockerAvailable) return;
  // Pre-pull the test image so the first test doesn't pay the latency.
  // Failure here is non-fatal — the pull-policy tests will retry.
  const docker = new Docker();
  try {
    const stream = await docker.pull(TEST_IMAGE);
    await new Promise<void>((resolve, reject) => {
      docker.modem.followProgress(stream, (err) => (err !== null ? reject(err) : resolve()));
    });
  } catch (err) {
    pullErrorMessage = err instanceof Error ? err.message : String(err);
  }
});

// eslint-disable-next-line agent-code-guard/async-keyword
afterAll(async () => {
  if (!dockerAvailable) return;
  // Best-effort cleanup of any stragglers — auto-tagged images from
  // build tests, leftover containers from interrupted runs.
  const docker = new Docker();
  try {
    const images = await docker.listImages({ filters: { reference: ["cc-judge-integration-*"] } });
    for (const summary of images) {
      try {
        await docker.getImage(summary.Id).remove({ force: true });
      } catch (err) {
        void err;
      }
    }
  } catch (err) {
    void err;
  }
});

function makePlan(scenario: string, agent: AgentDeclaration): RunPlan {
  return {
    project: ProjectId("cc-judge"),
    scenarioId: ScenarioId(scenario),
    name: scenario,
    description: `integration: ${scenario}`,
    agents: [agent],
    requirements: {
      expectedBehavior: "real docker round-trip",
      validationChecks: ["container start", "workspace mount"],
    },
  };
}

describe.skipIf(!dockerAvailable)("DockerRuntime (integration, real Docker)", () => {
  itEffect("prepare → stop cycle creates and reaps a real container", function* () {
    if (pullErrorMessage !== null) {
      // The image pull during beforeAll failed (rate limit, no
      // network, etc). Surface that instead of a noisier failure
      // later in the test body.
      expect.fail(`alpine:3.19 pull failed: ${pullErrorMessage}`);
    }
    const runtime = new DockerRuntime();
    const agent: AgentDeclaration = {
      id: AgentId("integration-prepare-stop"),
      name: "Integration Prepare/Stop",
      artifact: { _tag: "DockerImageArtifact", image: TEST_IMAGE, pullPolicy: "if-missing" },
      promptInputs: {},
    };
    const plan = makePlan(`integration-prepare-stop-${Date.now()}`, agent);

    const handle = (yield* runtime.prepare(agent, plan)) as RuntimeHandle & {
      readonly containerId?: string;
    };
    expect(typeof handle.containerId).toBe("string");
    expect(handle.containerId?.length ?? 0).toBeGreaterThan(0);
    expect(existsSync(handle.workspaceDir)).toBe(true);

    // Container is actually running per dockerode.
    const docker = new Docker();
    const inspect = yield* awaitDocker(() => docker.getContainer(handle.containerId ?? "").inspect());
    expect(inspect.State.Running).toBe(true);

    yield* runtime.stop(handle);

    // After stop, the workspace dir is gone and the container is no
    // longer present (AutoRemove + our explicit remove).
    expect(existsSync(handle.workspaceDir)).toBe(false);
    const stillThere = yield* Effect.either(
      Effect.tryPromise(() => docker.getContainer(handle.containerId ?? "").inspect()),
    );
    expect(stillThere._tag).toBe(EITHER_LEFT);
  });

  itEffect("pullPolicy 'never' fails when the image is not present locally", function* () {
    const runtime = new DockerRuntime();
    // Use a name that definitely does not exist locally.
    const phantomImage = `cc-judge-phantom-${Date.now()}:latest`;
    const agent: AgentDeclaration = {
      id: AgentId("integration-policy-never"),
      name: "Integration Policy Never",
      artifact: { _tag: "DockerImageArtifact", image: phantomImage, pullPolicy: "never" },
      promptInputs: {},
    };
    const plan = makePlan(`integration-policy-never-${Date.now()}`, agent);

    const result = yield* Effect.either(runtime.prepare(agent, plan));
    const error = expectLeft(result);
    expect(error.cause._tag).toBe("ImageMissing");
  });

  itEffect("DockerBuildArtifact end-to-end builds and runs the auto-tagged image", function* () {
    const repoRoot = mkdtempSync(path.join(os.tmpdir(), "cc-judge-int-build-"));
    const contextPath = path.join(repoRoot, "ctx");
    mkdirSync(contextPath, { recursive: true });
    writeFileSync(
      path.join(contextPath, "Dockerfile"),
      `FROM ${TEST_IMAGE}\nRUN echo hello > /built\n`,
      "utf8",
    );

    const runtime = new DockerRuntime();
    const agent: AgentDeclaration = {
      id: AgentId("integration-build"),
      name: "Integration Build",
      artifact: { _tag: "DockerBuildArtifact", contextPath },
      promptInputs: {},
    };
    const plan = makePlan(`integration-build-${Date.now()}`, agent);

    const handle = yield* runtime.prepare(agent, plan);
    expect(existsSync(handle.workspaceDir)).toBe(true);

    yield* runtime.stop(handle);

    expect(existsSync(handle.workspaceDir)).toBe(false);
    // Auto-tagged image was removed because removeOnStop was true
    // (artifact.imageTag was undefined).
    const docker = new Docker();
    const images = yield* awaitDocker(() =>
      docker.listImages({ filters: { reference: [`cc-judge-${plan.scenarioId}-*`] } }),
    );
    expect(images.length).toBe(0);
  });

  itEffect("DockerBuildArtifact failure removes the auto-tagged partial image", function* () {
    const repoRoot = mkdtempSync(path.join(os.tmpdir(), "cc-judge-int-build-fail-"));
    const contextPath = path.join(repoRoot, "ctx");
    mkdirSync(contextPath, { recursive: true });
    writeFileSync(
      path.join(contextPath, "Dockerfile"),
      // Intentionally fail: try to run a command that doesn't exist.
      `FROM ${TEST_IMAGE}\nRUN /this/binary/does/not/exist\n`,
      "utf8",
    );

    const runtime = new DockerRuntime();
    const scenarioId = `integration-build-fail-${Date.now()}`;
    const agent: AgentDeclaration = {
      id: AgentId("integration-build-fail"),
      name: "Integration Build Fail",
      artifact: { _tag: "DockerBuildArtifact", contextPath },
      promptInputs: {},
    };
    const plan = makePlan(scenarioId, agent);

    const result = yield* Effect.either(runtime.prepare(agent, plan));
    const error = expectLeft(result);
    expect(error.cause._tag).toBe("DockerBuildFailed");

    // No auto-tagged image left over.
    const docker = new Docker();
    const images = yield* awaitDocker(() =>
      docker.listImages({ filters: { reference: [`cc-judge-${scenarioId}-*`] } }),
    );
    expect(images.length).toBe(0);
  });

  itEffect("DockerBuildArtifact failure preserves a user-supplied imageTag", function* () {
    const repoRoot = mkdtempSync(path.join(os.tmpdir(), "cc-judge-int-build-userTag-"));
    const contextPath = path.join(repoRoot, "ctx");
    mkdirSync(contextPath, { recursive: true });
    writeFileSync(
      path.join(contextPath, "Dockerfile"),
      `FROM ${TEST_IMAGE}\nRUN /this/binary/does/not/exist\n`,
      "utf8",
    );

    const docker = new Docker();
    const userTag = `cc-judge-integration-usertag-${Date.now()}:test`;

    // First build a working image with the user tag so it's actually
    // present in the daemon. Then re-run with a failing Dockerfile to
    // assert the failure path doesn't yank the user's image.
    const buildStream = yield* awaitDocker(() =>
      docker.buildImage(
        { context: contextPath, src: ["Dockerfile"] },
        { t: userTag },
      ),
    );
    yield* Effect.async<void, never>((resume) => {
      docker.modem.followProgress(buildStream, () => resume(Effect.void));
    });

    // A separate Dockerfile that builds successfully so we can stage
    // the user image without depending on the broken Dockerfile we
    // wrote above. Overwrite, build, then break it again.
    writeFileSync(
      path.join(contextPath, "Dockerfile"),
      `FROM ${TEST_IMAGE}\nRUN echo ok\n`,
      "utf8",
    );
    const setupStream = yield* awaitDocker(() =>
      docker.buildImage({ context: contextPath, src: ["Dockerfile"] }, { t: userTag }),
    );
    yield* Effect.async<void, never>((resume) => {
      docker.modem.followProgress(setupStream, () => resume(Effect.void));
    });
    // Now break the Dockerfile so the next build fails.
    writeFileSync(
      path.join(contextPath, "Dockerfile"),
      `FROM ${TEST_IMAGE}\nRUN /this/binary/does/not/exist\n`,
      "utf8",
    );

    const runtime = new DockerRuntime();
    const agent: AgentDeclaration = {
      id: AgentId("integration-build-userTag"),
      name: "Integration Build UserTag",
      artifact: { _tag: "DockerBuildArtifact", contextPath, imageTag: userTag },
      promptInputs: {},
    };
    const plan = makePlan(`integration-build-userTag-${Date.now()}`, agent);

    const result = yield* Effect.either(runtime.prepare(agent, plan));
    expect(result._tag).toBe(EITHER_LEFT);

    // User-supplied tag is still present in the daemon.
    const inspectResult = yield* Effect.either(
      Effect.tryPromise(() => docker.getImage(userTag).inspect()),
    );
    expect(inspectResult._tag).toBe("Right");

    // Test cleanup: remove the user-staged image.
    yield* Effect.tryPromise(() => docker.getImage(userTag).remove({ force: true })).pipe(
      Effect.catchAll(() => Effect.void),
    );
  });
});

tests/judge-preflight.test.ts.source:
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
import { existsSync, mkdirSync, mkdtempSync, readFileSync, writeFileSync } from "node:fs";
import * as os from "node:os";
import * as path from "node:path";

const { spawnSyncMock } = vi.hoisted(() => ({
  spawnSyncMock: vi.fn(),
}));

vi.mock("node:child_process", () => ({
  spawnSync: spawnSyncMock,
}));

import {
  clearJudgePreflightDiskCacheForTests,
  ensureJudgeReady,
  resetJudgePreflightCacheForTests,
} from "../src/app/judge-preflight.js";
import { captureEnvVar, deleteEnvVar, restoreEnvVar, setEnvVar } from "./support/env.js";

// Disk cache lives at <xdgCacheHome>/cc-judge/anthropic-auth-success.json.
// `installXdgCacheHome` in beforeEach captures the per-test path so tests
// can read/seed the cache file without touching process.env at runtime.
let currentXdgCacheHome: string | null = null;

function installXdgCacheHome(): string {
  const dir = mkdtempSync(path.join(os.tmpdir(), "cc-judge-auth-cache-"));
  setEnvVar("XDG_CACHE_HOME", dir);
  currentXdgCacheHome = dir;
  return dir;
}

function cacheFilePath(): string {
  if (currentXdgCacheHome === null) {
    throw new Error("test invariant: installXdgCacheHome not called this test");
  }
  return path.join(currentXdgCacheHome, "cc-judge", "anthropic-auth-success.json");
}

const TWENTY_FOUR_HOURS_MS = 24 * 60 * 60 * 1_000;

const SAVED_XDG_CACHE_HOME = captureEnvVar("XDG_CACHE_HOME");
const SAVED_ANTHROPIC_API_KEY = captureEnvVar("ANTHROPIC_API_KEY");

describe("judge preflight cache", () => {
  beforeEach(() => {
    spawnSyncMock.mockReset();
    resetJudgePreflightCacheForTests();
    clearJudgePreflightDiskCacheForTests();
    installXdgCacheHome();
    deleteEnvVar("ANTHROPIC_API_KEY");
  });

  afterEach(() => {
    restoreEnvVar("XDG_CACHE_HOME", SAVED_XDG_CACHE_HOME);
    restoreEnvVar("ANTHROPIC_API_KEY", SAVED_ANTHROPIC_API_KEY);
  });

  it("skips preflight entirely when ANTHROPIC_API_KEY is set", () => {
    setEnvVar("ANTHROPIC_API_KEY", "test-key");

    expect(ensureJudgeReady("anthropic")).toBeNull();
    expect(spawnSyncMock).not.toHaveBeenCalled();
  });

  it("reuses the disk cache for back-to-back anthropic preflight calls", () => {
    spawnSyncMock.mockReturnValue({
      status: 0,
      stdout: JSON.stringify({ loggedIn: true }),
      stderr: "",
      error: undefined,
    });

    expect(ensureJudgeReady("anthropic")).toBeNull();
    expect(ensureJudgeReady("anthropic")).toBeNull();
    expect(spawnSyncMock).toHaveBeenCalledTimes(1);
  });

  it("re-runs preflight after the disk cache is cleared", () => {
    spawnSyncMock.mockReturnValue({
      status: 0,
      stdout: JSON.stringify({ loggedIn: true }),
      stderr: "",
      error: undefined,
    });

    expect(ensureJudgeReady("anthropic")).toBeNull();
    expect(spawnSyncMock).toHaveBeenCalledTimes(1);

    // No in-memory cache survives a disk cache clear: the next call
    // must hit `claude auth status` again.
    clearJudgePreflightDiskCacheForTests();
    expect(ensureJudgeReady("anthropic")).toBeNull();
    expect(spawnSyncMock).toHaveBeenCalledTimes(2);
  });

  it("does not cache a failing auth preflight", () => {
    spawnSyncMock.mockReturnValue({
      status: 1,
      stdout: "",
      stderr: "not logged in",
      error: undefined,
    });

    expect(ensureJudgeReady("anthropic")).toContain("claude auth preflight failed");
    expect(ensureJudgeReady("anthropic")).toContain("claude auth preflight failed");
    expect(spawnSyncMock).toHaveBeenCalledTimes(2);
  });

  it("skips anthropic auth preflight for non-anthropic backends", () => {
    expect(ensureJudgeReady("openai")).toBeNull();
    expect(spawnSyncMock).not.toHaveBeenCalled();
  });

  // ── disk cache validation paths ───────────────────────────────────────────

  it("re-runs preflight and rewrites cache when on-disk JSON is malformed", () => {
    spawnSyncMock.mockReturnValue({
      status: 0,
      stdout: JSON.stringify({ loggedIn: true }),
      stderr: "",
      error: undefined,
    });
    // Pre-stage a corrupt cache file.
    const cachePath = cacheFilePath();
    mkdirSync(path.dirname(cachePath), { recursive: true });
    writeFileSync(cachePath, "not json {{{", "utf8");

    expect(ensureJudgeReady("anthropic")).toBeNull();
    expect(spawnSyncMock).toHaveBeenCalledTimes(1);
    // Cache was rewritten with a valid record.
    const rewritten = JSON.parse(readFileSync(cachePath, "utf8")) as { checkedAtMs?: unknown };
    expect(typeof rewritten.checkedAtMs).toBe("number");
  });

  it("re-runs preflight when cached checkedAtMs is non-numeric", () => {
    spawnSyncMock.mockReturnValue({
      status: 0,
      stdout: JSON.stringify({ loggedIn: true }),
      stderr: "",
      error: undefined,
    });
    const cachePath = cacheFilePath();
    mkdirSync(path.dirname(cachePath), { recursive: true });
    writeFileSync(cachePath, JSON.stringify({ checkedAtMs: "yesterday" }), "utf8");

    expect(ensureJudgeReady("anthropic")).toBeNull();
    expect(spawnSyncMock).toHaveBeenCalledTimes(1);
  });

  it("re-runs preflight when cached checkedAtMs is older than the 24h TTL", () => {
    spawnSyncMock.mockReturnValue({
      status: 0,
      stdout: JSON.stringify({ loggedIn: true }),
      stderr: "",
      error: undefined,
    });
    const cachePath = cacheFilePath();
    mkdirSync(path.dirname(cachePath), { recursive: true });
    // Pin the timestamp to two days ago so the TTL boundary is unambiguous.
    const expiredCheckedAt = Date.now() - 2 * TWENTY_FOUR_HOURS_MS;
    writeFileSync(cachePath, JSON.stringify({ checkedAtMs: expiredCheckedAt }), "utf8");

    expect(ensureJudgeReady("anthropic")).toBeNull();
    expect(spawnSyncMock).toHaveBeenCalledTimes(1);
    // Cache was overwritten — no longer expired.
    const rewritten = JSON.parse(readFileSync(cachePath, "utf8")) as { checkedAtMs: number };
    expect(rewritten.checkedAtMs).toBeGreaterThan(expiredCheckedAt);
  });

  it("re-runs preflight when cache JSON is missing the checkedAtMs key entirely", () => {
    spawnSyncMock.mockReturnValue({
      status: 0,
      stdout: JSON.stringify({ loggedIn: true }),
      stderr: "",
      error: undefined,
    });
    const cachePath = cacheFilePath();
    mkdirSync(path.dirname(cachePath), { recursive: true });
    writeFileSync(cachePath, JSON.stringify({ wrong: "shape" }), "utf8");

    expect(ensureJudgeReady("anthropic")).toBeNull();
    expect(spawnSyncMock).toHaveBeenCalledTimes(1);
  });

  it("re-runs preflight when cache root JSON is null", () => {
    spawnSyncMock.mockReturnValue({
      status: 0,
      stdout: JSON.stringify({ loggedIn: true }),
      stderr: "",
      error: undefined,
    });
    const cachePath = cacheFilePath();
    mkdirSync(path.dirname(cachePath), { recursive: true });
    writeFileSync(cachePath, JSON.stringify(null), "utf8");

    expect(ensureJudgeReady("anthropic")).toBeNull();
    expect(spawnSyncMock).toHaveBeenCalledTimes(1);
  });

  it("re-runs preflight when checkedAtMs is Infinity (non-finite)", () => {
    spawnSyncMock.mockReturnValue({
      status: 0,
      stdout: JSON.stringify({ loggedIn: true }),
      stderr: "",
      error: undefined,
    });
    const cachePath = cacheFilePath();
    mkdirSync(path.dirname(cachePath), { recursive: true });
    // JSON.stringify converts Infinity to null, so write a hand-crafted
    // body that JSON.parse will return Infinity for is impossible. Use NaN
    // path: write `{"checkedAtMs":null}` which fails the typeof check via
    // `parsed.checkedAtMs` being null, not number.
    writeFileSync(cachePath, '{"checkedAtMs":null}', "utf8");

    expect(ensureJudgeReady("anthropic")).toBeNull();
    expect(spawnSyncMock).toHaveBeenCalledTimes(1);
  });

  // ── claude binary failure modes ───────────────────────────────────────────

  it("surfaces an ENOENT-like result.error from spawnSync as 'preflight failed'", () => {
    spawnSyncMock.mockReturnValue({
      status: null,
      stdout: "",
      stderr: "",
      error: new Error("spawn claude ENOENT"),
    });

    const result = ensureJudgeReady("anthropic");
    expect(result).toContain("claude auth preflight failed");
    expect(result).toContain("ENOENT");
    // Failed preflight does NOT write a success cache.
    expect(existsSync(cacheFilePath())).toBe(false);
  });

  it("returns the trimmed stderr when claude exits non-zero with a message", () => {
    spawnSyncMock.mockReturnValue({
      status: 1,
      stdout: "",
      stderr: "  not logged in  \n",
      error: undefined,
    });

    const result = ensureJudgeReady("anthropic");
    expect(result).toContain("not logged in");
    // Surrounding whitespace was trimmed out of the message.
    expect(result).not.toMatch(/\s\snot logged in/u);
  });

  it("returns a generic 'preflight failed' when stderr is empty on non-zero exit", () => {
    spawnSyncMock.mockReturnValue({
      status: 2,
      stdout: "",
      stderr: "",
      error: undefined,
    });

    expect(ensureJudgeReady("anthropic")).toBe("claude auth preflight failed");
  });

  it("treats malformed JSON stdout as an invalid-JSON preflight failure", () => {
    spawnSyncMock.mockReturnValue({
      status: 0,
      stdout: "this is not json",
      stderr: "",
      error: undefined,
    });

    const result = ensureJudgeReady("anthropic");
    expect(result).toContain("invalid JSON");
    expect(existsSync(cacheFilePath())).toBe(false);
  });

  it("treats loggedIn=false as the 'auth missing' message and does not cache", () => {
    spawnSyncMock.mockReturnValue({
      status: 0,
      stdout: JSON.stringify({ loggedIn: false }),
      stderr: "",
      error: undefined,
    });

    const result = ensureJudgeReady("anthropic");
    expect(result).toContain("claude auth missing");
    expect(result).toContain("claude auth login");
    expect(result).toContain("ANTHROPIC_API_KEY");
    expect(existsSync(cacheFilePath())).toBe(false);
  });

  it("treats stdout without a loggedIn key as 'auth missing'", () => {
    spawnSyncMock.mockReturnValue({
      status: 0,
      stdout: JSON.stringify({ otherField: 1 }),
      stderr: "",
      error: undefined,
    });

    expect(ensureJudgeReady("anthropic")).toContain("claude auth missing");
    expect(existsSync(cacheFilePath())).toBe(false);
  });

  // ── disk cache write side effect ──────────────────────────────────────────

  it("writes a success cache atomically (no .tmp leftover after successful preflight)", () => {
    spawnSyncMock.mockReturnValue({
      status: 0,
      stdout: JSON.stringify({ loggedIn: true }),
      stderr: "",
      error: undefined,
    });

    expect(ensureJudgeReady("anthropic")).toBeNull();

    const cachePath = cacheFilePath();
    expect(existsSync(cachePath)).toBe(true);
    // The atomic write uses ${cachePath}.${pid}.tmp; no such file should
    // remain after a successful renameSync.
    const tmpPath = `${cachePath}.${process.pid}.tmp`;
    expect(existsSync(tmpPath)).toBe(false);
  });
});

tests/bundle-codec-pbt.test.ts.source:
// Property-based tests for the bundle codec round-trip.
// One roundtrip property kills many mutants in encode/decode/normalize
// because every JSON or YAML string and every field rebuild gets exercised
// against generated bundles spanning the schema's input domain.

import { describe, expect } from "vitest";
import { Data, Effect } from "effect";
import * as fc from "fast-check";
import {
  bundleAutoCodec,
  bundleJsonCodec,
  bundleYamlCodec,
  type BundleCodec,
} from "../src/emit/bundle-codec.js";
import { BundleDecodeError } from "../src/core/errors.js";

// Tagged error for fast-check rejections so the test's Effect channel
// stays typed (no generic Error). The message field carries fast-check's
// shrunk-counterexample report verbatim.
class PbtAssertionError extends Data.TaggedError("PbtAssertionError")<{
  readonly message: string;
}> {}
import {
  AGENT_LIFECYCLE_STATUS,
  AgentId,
  ProjectId,
  RunId,
  ScenarioId,
  type AgentLifecycleStatus,
  type AgentOutcome,
  type AgentRef,
  type AgentTurn,
  type JudgmentBundle,
} from "../src/core/types.js";
import { itEffect, expectLeft } from "./support/effect.js";

const PROPERTY_RUNS = 50;

// ── arbitraries ─────────────────────────────────────────────────────────────

// Identifiers must satisfy the schema (minLength 1, maxLength 256). Strings
// of arbitrary unicode are fine for the json codec but YAML round-trips need
// us to avoid characters YAML treats as control (newline at start, leading
// dash with space) — restrict to a printable subset for stable round-trips.
const idArb = fc
  .string({ minLength: 1, maxLength: 64 })
  .filter((s) => /^[A-Za-z0-9_./:@-]+$/u.test(s));

const arbitraryString = fc.string({ minLength: 0, maxLength: 200 });
const nonEmptyString = fc.string({ minLength: 1, maxLength: 200 });

const lifecycleStatusArb: fc.Arbitrary<AgentLifecycleStatus> = fc.constantFrom(
  AGENT_LIFECYCLE_STATUS.Completed,
  AGENT_LIFECYCLE_STATUS.TimedOut,
  AGENT_LIFECYCLE_STATUS.FailedToStart,
  AGENT_LIFECYCLE_STATUS.RuntimeError,
  AGENT_LIFECYCLE_STATUS.Cancelled,
);

const isoDateArb = fc
  .date({ noInvalidDate: true })
  .map((d) => d.toISOString());

const agentRefArb: fc.Arbitrary<AgentRef> = fc.record(
  {
    id: idArb,
    name: nonEmptyString,
    role: fc.option(arbitraryString, { nil: undefined }),
  },
  { requiredKeys: ["id", "name"] },
);

const turnArb = fc.record({
  index: fc.nat(),
  prompt: arbitraryString,
  response: arbitraryString,
  startedAt: isoDateArb,
  latencyMs: fc.nat(),
  toolCallCount: fc.nat(),
  inputTokens: fc.nat(),
  outputTokens: fc.nat(),
  cacheReadTokens: fc.nat(),
  cacheWriteTokens: fc.nat(),
});

const agentTurnArb = (agentIds: ReadonlyArray<string>): fc.Arbitrary<AgentTurn> =>
  fc.record(
    {
      turn: turnArb,
      agentId: fc.option(fc.constantFrom(...agentIds), { nil: undefined }),
    },
    { requiredKeys: ["turn"] },
  ).map((t) => (t.agentId === undefined ? { turn: t.turn } : { turn: t.turn, agentId: AgentId(t.agentId) }));

const outcomeArb = (agentIds: ReadonlyArray<string>): fc.Arbitrary<AgentOutcome> =>
  fc.record(
    {
      agentId: fc.constantFrom(...agentIds),
      status: lifecycleStatusArb,
      startedAt: fc.option(isoDateArb, { nil: undefined }),
      endedAt: isoDateArb,
      exitCode: fc.option(fc.integer(), { nil: undefined }),
      reason: fc.option(arbitraryString, { nil: undefined }),
    },
    { requiredKeys: ["agentId", "status", "endedAt"] },
  ).map((o) => ({ ...o, agentId: AgentId(o.agentId) }));

// One JudgmentBundle generator. Each agent gets exactly one outcome
// (the schema requires outcomes for every agent named).
const bundleArb: fc.Arbitrary<JudgmentBundle> = fc
  .uniqueArray(idArb, { minLength: 1, maxLength: 4 })
  .chain((agentIds) =>
    fc
      .record({
        runId: idArb,
        project: idArb,
        scenarioId: idArb,
        name: nonEmptyString,
        description: arbitraryString,
        requirements: fc.record({
          expectedBehavior: arbitraryString,
          validationChecks: fc.array(nonEmptyString, { maxLength: 5 }),
        }),
        turns: fc.option(fc.array(agentTurnArb(agentIds), { maxLength: 5 }), {
          nil: undefined,
        }),
      })
      .chain((base) =>
        fc
          .array(outcomeArb(agentIds), {
            minLength: agentIds.length,
            maxLength: agentIds.length,
          })
          // Pin outcomes to the agentIds so each agent gets exactly one.
          .map((outcomes) => {
            const pinned: AgentOutcome[] = agentIds.map((id, i) => {
              const candidate = outcomes[i];
              if (candidate === undefined) {
                throw new Error("invariant: outcome generator must produce one per agent");
              }
              return { ...candidate, agentId: AgentId(id) };
            });
            return pinned;
          })
          .map((outcomes): JudgmentBundle => ({
            runId: RunId(base.runId),
            project: ProjectId(base.project),
            scenarioId: ScenarioId(base.scenarioId),
            name: base.name,
            description: base.description,
            requirements: base.requirements,
            agents: agentIds.map(
              (id): AgentRef => ({ id, name: `agent-${id}` }),
            ),
            ...(base.turns !== undefined ? { turns: base.turns } : {}),
            outcomes,
          })),
      ),
  );

// ── round-trip property ─────────────────────────────────────────────────────

function roundTripEff(
  codec: BundleCodec,
  bundle: JudgmentBundle,
): Effect.Effect<void, BundleDecodeError, never> {
  return Effect.gen(function* () {
    const encoded = yield* codec.encode(bundle);
    const decoded = yield* codec.decode(encoded, "mem://pbt");

    expect(decoded.runId).toBe(bundle.runId);
    expect(decoded.project).toBe(bundle.project);
    expect(decoded.scenarioId).toBe(bundle.scenarioId);
    expect(decoded.name).toBe(bundle.name);
    expect(decoded.description).toBe(bundle.description);
    expect(decoded.agents.length).toBe(bundle.agents.length);
    for (let i = 0; i < bundle.agents.length; i++) {
      expect(decoded.agents[i]?.id).toBe(bundle.agents[i]?.id);
    }
    expect(decoded.outcomes.length).toBe(bundle.outcomes.length);
    for (let i = 0; i < bundle.outcomes.length; i++) {
      expect(decoded.outcomes[i]?.agentId).toBe(bundle.outcomes[i]?.agentId);
      expect(decoded.outcomes[i]?.status).toBe(bundle.outcomes[i]?.status);
      expect(decoded.outcomes[i]?.endedAt).toBe(bundle.outcomes[i]?.endedAt);
    }
    if (bundle.turns !== undefined) {
      expect(decoded.turns?.length).toBe(bundle.turns.length);
    } else {
      expect(decoded.turns).toBeUndefined();
    }
  });
}

// fast-check's runner is sync-or-promise; bridge into Effect.tryPromise so
// rejected promises surface through the typed channel rather than being
// swallowed as defects (no-Effect.promise lint rule).
//
// Inside the property: Effect.runPromise rejects on the codec's
// BundleDecodeError, fast-check sees the rejection as a property failure
// and shrinks toward the smallest bundle that reproduces it. The
// shrunk bundle's tagged error is in the rejection's message — which is
// exactly the diagnostic info we want.
function assertProperty(
  codec: BundleCodec,
): Effect.Effect<void, PbtAssertionError, never> {
  return Effect.tryPromise({
    try: () =>
      fc.assert(
        fc.asyncProperty(bundleArb, (bundle) =>
          Effect.runPromise(roundTripEff(codec, bundle)),
        ),
        { numRuns: PROPERTY_RUNS },
      ),
    catch: (err) =>
      new PbtAssertionError({ message: err instanceof Error ? err.message : String(err) }),
  });
}

describe("BundleCodec round-trip (PBT)", () => {
  itEffect("json: encode → decode preserves all structural fields", function* () {
    yield* assertProperty(bundleJsonCodec);
  });

  itEffect("yaml: encode → decode preserves all structural fields", function* () {
    yield* assertProperty(bundleYamlCodec);
  });

  itEffect("auto: detects JSON when input starts with '{' after trim", function* () {
    yield* assertProperty(bundleAutoCodec);
  });
});

describe("bundleAutoCodec dispatch (example-based, mutation killer)", () => {
  // Every branch in the auto-codec dispatch needs an example. PBT above
  // mostly hits the JSON branch (auto-encodes as JSON); these tests force
  // the YAML branch and the leading-whitespace edge case.

  itEffect("auto: dispatches to YAML when input does not start with { or [", function* () {
    const yaml = [
      "runId: yaml-dispatch",
      "project: cc-judge",
      "scenarioId: scn",
      "name: y",
      "description: d",
      "requirements:",
      "  expectedBehavior: ok",
      "  validationChecks: []",
      "agents:",
      "  - id: a",
      "    name: A",
      "outcomes:",
      "  - agentId: a",
      "    status: completed",
      "    endedAt: 2026-04-29T00:00:00.000Z",
    ].join("\n");

    const bundle = yield* bundleAutoCodec.decode(yaml, "mem://yaml");
    expect(bundle.runId).toBe("yaml-dispatch");
  });

  itEffect("auto: trims leading whitespace before dispatch decision", function* () {
    const json = "   \n\t  " + JSON.stringify({
      runId: "ws-dispatch",
      project: "cc-judge",
      scenarioId: "scn",
      name: "j",
      description: "d",
      requirements: { expectedBehavior: "ok", validationChecks: [] },
      agents: [{ id: "a", name: "A" }],
      outcomes: [{ agentId: "a", status: "completed", endedAt: "2026-04-29T00:00:00.000Z" }],
    });

    const bundle = yield* bundleAutoCodec.decode(json, "mem://ws");
    expect(bundle.runId).toBe("ws-dispatch");
  });

  itEffect("auto: dispatches to JSON when input starts with [", function* () {
    // Top-level array fails the schema (bundles are objects), but the
    // dispatcher should still route to JSON, not YAML. Reaching the
    // schema validator (with the input path threaded through) proves
    // JSON.parse succeeded.
    const arrayJson = "[1, 2, 3]";
    const result = yield* Effect.either(bundleAutoCodec.decode(arrayJson, "mem://arr"));
    const error = expectLeft(result);
    expect(error.cause._tag).toBe("SchemaInvalid");
    if (error.cause._tag === "SchemaInvalid") {
      expect(error.cause.path).toBe("mem://arr");
    }
  });
});

tests/wal-pbt.test.ts.source:
// Property-based tests for pure helpers in src/emit/wal.ts.
// These exist to kill mutation-test survivors that example-based tests
// only hit narrowly. Each fc.property generates many inputs across the
// relevant input domain in a single test case.

import { describe, expect, it } from "vitest";
import * as fc from "fast-check";
import {
  PAYLOAD_PREVIEW_MAX_CHARS,
  WAL_LINE_KIND,
  errorToString,
  isEnoent,
  isOutcomeLine,
  previewPayload,
  walPathsFromResultsDir,
} from "../src/emit/wal.js";
import * as path from "node:path";

const PROPERTY_RUNS = 200;

describe("previewPayload (PBT)", () => {
  it("returns a string for any input", () => {
    fc.assert(
      fc.property(fc.anything(), (payload) => {
        expect(typeof previewPayload(payload)).toBe("string");
      }),
      { numRuns: PROPERTY_RUNS },
    );
  });

  it("output length never exceeds the cap plus one ellipsis char", () => {
    fc.assert(
      fc.property(fc.anything(), (payload) => {
        const out = previewPayload(payload);
        expect(out.length).toBeLessThanOrEqual(PAYLOAD_PREVIEW_MAX_CHARS + 1);
      }),
      { numRuns: PROPERTY_RUNS },
    );
  });

  it("appends an ellipsis iff the JSON form exceeds the cap", () => {
    fc.assert(
      fc.property(fc.anything(), (payload) => {
        const out = previewPayload(payload);
        let serialized: string | undefined;
        try {
          serialized = JSON.stringify(payload);
        } catch (err) {
          void err;
          serialized = undefined;
        }
        if (serialized === undefined) {
          expect(out).toBe("<unstringifiable>");
          return;
        }
        if (serialized.length > PAYLOAD_PREVIEW_MAX_CHARS) {
          expect(out.endsWith("…")).toBe(true);
          expect(out.length).toBe(PAYLOAD_PREVIEW_MAX_CHARS + 1);
        } else {
          expect(out).toBe(serialized);
          expect(out.endsWith("…")).toBe(false);
        }
      }),
      { numRuns: PROPERTY_RUNS },
    );
  });

  it("preserves the JSON prefix when truncating", () => {
    // Build payloads guaranteed to exceed the cap so we always hit the
    // truncate branch; the first PAYLOAD_PREVIEW_MAX_CHARS chars must
    // match the head of JSON.stringify exactly.
    fc.assert(
      fc.property(
        fc.string({ minLength: PAYLOAD_PREVIEW_MAX_CHARS + 50 }),
        (longString) => {
          const out = previewPayload(longString);
          const serialized = JSON.stringify(longString);
          expect(out.slice(0, PAYLOAD_PREVIEW_MAX_CHARS)).toBe(
            serialized.slice(0, PAYLOAD_PREVIEW_MAX_CHARS),
          );
        },
      ),
      { numRuns: PROPERTY_RUNS },
    );
  });

  it("returns '<unstringifiable>' for values JSON.stringify cannot serialize", () => {
    // Functions and undefined both make JSON.stringify return undefined.
    fc.assert(
      fc.property(
        fc.oneof(
          fc.constant(undefined),
          fc.constant(() => undefined),
          fc.constant(Symbol("x")),
        ),
        (payload) => {
          expect(previewPayload(payload)).toBe("<unstringifiable>");
        },
      ),
      { numRuns: 50 },
    );
  });

  it("returns '<unstringifiable>' on circular references (JSON.stringify throws)", () => {
    const circular: { self?: unknown } = {};
    circular.self = circular;
    expect(previewPayload(circular)).toBe("<unstringifiable>");
  });

  it("returns the raw JSON for short payloads (no ellipsis suffix)", () => {
    fc.assert(
      fc.property(
        fc.oneof(
          fc.boolean(),
          fc.integer(),
          fc.constantFrom(null, 0, "", "x"),
        ),
        (payload) => {
          const out = previewPayload(payload);
          expect(out).toBe(JSON.stringify(payload));
          expect(out.endsWith("…")).toBe(false);
        },
      ),
      { numRuns: PROPERTY_RUNS },
    );
  });
});

// ── isOutcomeLine ───────────────────────────────────────────────────────────

describe("isOutcomeLine (PBT)", () => {
  it("returns false for non-object inputs", () => {
    fc.assert(
      fc.property(
        fc.oneof(
          fc.constant(null),
          fc.constant(undefined),
          fc.boolean(),
          fc.integer(),
          fc.string(),
        ),
        (value) => {
          expect(isOutcomeLine(value)).toBe(false);
        },
      ),
      { numRuns: PROPERTY_RUNS },
    );
  });

  it("returns true iff the object's kind field equals WAL_LINE_KIND.Outcome", () => {
    fc.assert(
      fc.property(
        fc.dictionary(fc.string(), fc.anything()),
        fc.string(),
        (extras, kindValue) => {
          const obj = { ...extras, kind: kindValue };
          if (kindValue === WAL_LINE_KIND.Outcome) {
            expect(isOutcomeLine(obj)).toBe(true);
          } else {
            expect(isOutcomeLine(obj)).toBe(false);
          }
        },
      ),
      { numRuns: PROPERTY_RUNS },
    );
  });

  it("returns false for objects without a kind field", () => {
    fc.assert(
      fc.property(
        fc
          .dictionary(fc.string(), fc.anything())
          .filter((o) => !("kind" in o)),
        (obj) => {
          expect(isOutcomeLine(obj)).toBe(false);
        },
      ),
      { numRuns: PROPERTY_RUNS },
    );
  });

  it("recognises a concrete outcome line shape", () => {
    expect(
      isOutcomeLine({ v: 1, runId: "r", seq: 5, ts: 0, kind: WAL_LINE_KIND.Outcome, payload: {} }),
    ).toBe(true);
  });
});

// ── errorToString ───────────────────────────────────────────────────────────

describe("errorToString (PBT)", () => {
  it("returns Error.message for Error instances", () => {
    fc.assert(
      fc.property(fc.string(), (msg) => {
        expect(errorToString(new Error(msg))).toBe(msg);
      }),
      { numRuns: PROPERTY_RUNS },
    );
  });

  it("returns String(value) for non-Error inputs", () => {
    fc.assert(
      fc.property(
        fc.oneof(
          fc.constant(null),
          fc.constant(undefined),
          fc.boolean(),
          fc.integer(),
          fc.string(),
        ),
        (value) => {
          expect(errorToString(value)).toBe(String(value));
        },
      ),
      { numRuns: PROPERTY_RUNS },
    );
  });

  it("returns a non-empty string for any input", () => {
    fc.assert(
      fc.property(fc.anything(), (value) => {
        const out = errorToString(value);
        expect(typeof out).toBe("string");
      }),
      { numRuns: PROPERTY_RUNS },
    );
  });

  it("falls back to '<unstringifiable error>' when String() throws", () => {
    // Object with a throwing toString — String(obj) calls toString which
    // throws — exercises the catch branch.
    const hostile = {
      toString(): string {
        throw new Error("nope");
      },
    };
    expect(errorToString(hostile)).toBe("<unstringifiable error>");
  });
});

// ── isEnoent ────────────────────────────────────────────────────────────────

describe("isEnoent (PBT)", () => {
  it("returns false for non-object inputs", () => {
    fc.assert(
      fc.property(
        fc.oneof(
          fc.constant(null),
          fc.constant(undefined),
          fc.boolean(),
          fc.integer(),
          fc.string(),
        ),
        (value) => {
          expect(isEnoent(value)).toBe(false);
        },
      ),
      { numRuns: PROPERTY_RUNS },
    );
  });

  it("returns true iff the object has code === 'ENOENT'", () => {
    fc.assert(
      fc.property(
        fc.dictionary(fc.string(), fc.anything()),
        fc.string(),
        (extras, code) => {
          const obj = { ...extras, code };
          if (code === "ENOENT") {
            expect(isEnoent(obj)).toBe(true);
          } else {
            expect(isEnoent(obj)).toBe(false);
          }
        },
      ),
      { numRuns: PROPERTY_RUNS },
    );
  });

  it("returns false for an object with code === 'EACCES' (close miss)", () => {
    expect(isEnoent({ code: "EACCES" })).toBe(false);
  });
});

// ── walPathsFromResultsDir ──────────────────────────────────────────────────

describe("walPathsFromResultsDir (PBT)", () => {
  it("inflightDir is always under resultsDir", () => {
    fc.assert(
      fc.property(fc.string({ minLength: 1 }), (resultsDir) => {
        const paths = walPathsFromResultsDir(resultsDir);
        expect(paths.resultsDir).toBe(resultsDir);
        expect(paths.inflightDir).toBe(path.join(resultsDir, "inflight"));
        expect(paths.runsDir).toBe(path.join(resultsDir, "runs"));
      }),
      { numRuns: PROPERTY_RUNS },
    );
  });

  it("inflightDir and runsDir are siblings (different basenames)", () => {
    fc.assert(
      fc.property(fc.string({ minLength: 1 }), (resultsDir) => {
        const paths = walPathsFromResultsDir(resultsDir);
        expect(path.dirname(paths.inflightDir)).toBe(path.dirname(paths.runsDir));
        expect(path.basename(paths.inflightDir)).not.toBe(path.basename(paths.runsDir));
      }),
      { numRuns: PROPERTY_RUNS },
    );
  });
});

