import { mkdtempSync } from "node:fs";
import * as os from "node:os";
import * as path from "node:path";
import { describe, expect, vi } from "vitest";

const { randomUUIDMock } = vi.hoisted(() => ({
  randomUUIDMock: vi.fn(),
}));

vi.mock("node:crypto", () => ({
  randomUUID: randomUUIDMock,
}));
import { Effect } from "effect";
import { runWithHarness } from "../src/app/pipeline.js";
import {
  AgentStartErrorCause,
  HarnessExecutionCause,
  RunCoordinationCause,
  RunCoordinationError,
} from "../src/core/errors.js";
import type { JudgeBackend } from "../src/judge/index.js";
import {
  AgentId,
  ProjectId,
  ScenarioId,
  type AgentDeclaration,
  type RunPlan,
} from "../src/core/types.js";
import { itEffect } from "./support/effect.js";

function makePlan(): RunPlan {
  const agents: readonly [AgentDeclaration, AgentDeclaration] = [
    {
      id: AgentId("alpha"),
      name: "Alpha",
      artifact: { _tag: "DockerImageArtifact", image: "repo/alpha:latest" },
      promptInputs: {},
    },
    {
      id: AgentId("beta"),
      name: "Beta",
      artifact: { _tag: "DockerImageArtifact", image: "repo/beta:latest" },
      promptInputs: {},
    },
  ];
  return {
    project: ProjectId("cc-judge"),
    scenarioId: ScenarioId("planned-failure"),
    name: "planned-failure",
    description: "planned failure path",
    agents,
    requirements: {
      expectedBehavior: "fold failures deterministically",
      validationChecks: ["no judge call on coordinator failure"],
    },
  };
}

const unusedHarness = {
  name: "unused",
  run() {
    return Effect.void;
  },
};

describe("runWithHarness failure folding", () => {
  itEffect("folds agent-start failure deterministically without invoking the judge", function* () {
    let judgeCalled = false;
    const judge: JudgeBackend = {
      name: "should-not-run",
      judge() {
        judgeCalled = true;
        return Effect.die("judge should not run for coordinator failures");
      },
    };
    const coordinator = {
      execute() {
        return Effect.fail(
          new RunCoordinationError({
            cause: RunCoordinationCause.AgentStartFailed({
              agentId: "alpha",
              detail: AgentStartErrorCause.BuildContextMissing({
                path: "/tmp/missing-context",
              }),
            }),
          }),
        );
      },
    };

    const report = yield* runWithHarness(makePlan(), unusedHarness, {
      coordinator,
      judge,
      resultsDir: mkdtempSync(path.join(os.tmpdir(), "cc-judge-fold-start-")),
    });

    expect(judgeCalled).toBe(false);
    expect(report.summary.failed).toBe(1);
    expect(report.runs[0]?.judgeModel).toBe("deterministic/coordinator");
    expect(report.runs[0]?.reason).toContain("alpha failed_to_start");
    expect(report.runs[0]?.reason).toContain("beta cancelled");
  });

  itEffect("preserves cancelled status when the run is aborted", function* () {
    const abortController = new AbortController();
    abortController.abort();
    const judge: JudgeBackend = {
      name: "should-not-run",
      judge() {
        return Effect.die("judge should not run for cancelled coordinator failures");
      },
    };
    const coordinator = {
      execute() {
        return Effect.fail(
          new RunCoordinationError({
            cause: RunCoordinationCause.HarnessFailed({
              detail: HarnessExecutionCause.ExecutionFailed({
                message: "aborted",
              }),
            }),
          }),
        );
      },
    };

    const report = yield* runWithHarness(makePlan(), unusedHarness, {
      coordinator,
      judge,
      abortSignal: abortController.signal,
      resultsDir: mkdtempSync(path.join(os.tmpdir(), "cc-judge-fold-cancel-")),
    });

    expect(report.summary.failed).toBe(1);
    expect(report.runs[0]?.reason).toContain("alpha cancelled");
    expect(report.runs[0]?.reason).toContain("beta cancelled");
    expect(report.runs[0]?.reason).not.toContain("runtime_error");
  });

  itEffect("uses a unique runId for each deterministic failure bundle", function* () {
    const judge: JudgeBackend = {
      name: "should-not-run",
      judge() {
        return Effect.die("judge should not run for coordinator failures");
      },
    };
    const coordinator = {
      execute() {
        return Effect.fail(
          new RunCoordinationError({
            cause: RunCoordinationCause.HarnessFailed({
              detail: HarnessExecutionCause.ExecutionFailed({
                message: "aborted",
              }),
            }),
          }),
        );
      },
    };
    const nowSpy = vi.spyOn(Date, "now").mockReturnValue(1_726_000_000_000);
    randomUUIDMock.mockReturnValueOnce("run-one").mockReturnValueOnce("run-two");
    try {
      yield* runWithHarness(makePlan(), unusedHarness, {
        coordinator,
        judge,
        resultsDir: mkdtempSync(path.join(os.tmpdir(), "cc-judge-fold-runid-1-")),
      });
      yield* runWithHarness(makePlan(), unusedHarness, {
        coordinator,
        judge,
        resultsDir: mkdtempSync(path.join(os.tmpdir(), "cc-judge-fold-runid-2-")),
      });
      expect(randomUUIDMock.mock.calls.length).toBeGreaterThanOrEqual(2);
    } finally {
      nowSpy.mockRestore();
      randomUUIDMock.mockReset();
    }
  });
});

tests/cli-smoke.test.ts.source:
// Smoke tests for the @effect/cli-based main() entrypoint.
// These cover parse-path branches that the integration tests in
// tests/plans.test.ts and tests/cli-auth-preflight.test.ts don't reach:
// missing positional, invalid integer, unknown flag, missing --bin
// when --runtime subprocess is set.

import { describe, expect, vi } from "vitest";
import { Effect } from "effect";

// Stub the pipeline so the run command never actually executes.
vi.mock("../src/app/pipeline.js", () => ({
  runPlans: vi.fn(() =>
    Effect.succeed({
      runs: [],
      summary: { total: 0, passed: 0, failed: 0, avgLatencyMs: 0 },
    }),
  ),
}));

// Make the auth preflight a no-op for parse-only paths.
vi.mock("../src/app/judge-preflight.js", () => ({
  ensureJudgeReady: vi.fn(() => null),
}));

import { main } from "../src/app/cli.js";
import { itEffect } from "./support/effect.js";
import { captureStream } from "./support/streams.js";
import { installDefaultEnvVar } from "./support/env.js";

installDefaultEnvVar("ANTHROPIC_API_KEY", "test-anthropic-api-key");

const EXIT_FATAL = 2;

describe("cli main() parse-path smoke tests", () => {
  itEffect("rejects unknown subcommand with exit 2", function* () {
    const stderr = captureStream(process.stderr);
    const stdout = captureStream(process.stdout);
    try {
      const code = yield* main(["does-not-exist"]);
      expect(code).toBe(EXIT_FATAL);
    } finally {
      stderr.restore();
      stdout.restore();
    }
  });

  itEffect("rejects 'run' with no positional argument with exit 2", function* () {
    const stderr = captureStream(process.stderr);
    const stdout = captureStream(process.stdout);
    try {
      const code = yield* main(["run"]);
      expect(code).toBe(EXIT_FATAL);
    } finally {
      stderr.restore();
      stdout.restore();
    }
  });

  itEffect("rejects --concurrency with non-integer value with exit 2", function* () {
    const stderr = captureStream(process.stderr);
    const stdout = captureStream(process.stdout);
    try {
      const code = yield* main(["run", "plan.yaml", "--concurrency", "abc"]);
      expect(code).toBe(EXIT_FATAL);
    } finally {
      stderr.restore();
      stdout.restore();
    }
  });

  itEffect("rejects unknown --flag with exit 2", function* () {
    const stderr = captureStream(process.stderr);
    const stdout = captureStream(process.stdout);
    try {
      const code = yield* main(["run", "plan.yaml", "--this-flag-doesnt-exist"]);
      expect(code).toBe(EXIT_FATAL);
    } finally {
      stderr.restore();
      stdout.restore();
    }
  });

  itEffect("rejects --log-level with invalid choice with exit 2", function* () {
    const stderr = captureStream(process.stderr);
    const stdout = captureStream(process.stdout);
    try {
      const code = yield* main(["run", "plan.yaml", "--log-level", "verbose"]);
      expect(code).toBe(EXIT_FATAL);
    } finally {
      stderr.restore();
      stdout.restore();
    }
  });

  itEffect("rejects --runtime subprocess without --bin with exit 2", function* () {
    const stderr = captureStream(process.stderr);
    const stdout = captureStream(process.stdout);
    try {
      const code = yield* main([
        "run",
        "plan.yaml",
        "--runtime",
        "subprocess",
        "--log-level",
        "error",
      ]);
      expect(code).toBe(EXIT_FATAL);
      const stderrText = stderr.chunks.join("");
      expect(stderrText).toContain("runtime resolution failed");
      expect(stderrText).toContain("missing --bin");
    } finally {
      stderr.restore();
      stdout.restore();
    }
  });

  itEffect("--help on the root command exits cleanly", function* () {
    const stderr = captureStream(process.stderr);
    const stdout = captureStream(process.stdout);
    try {
      const code = yield* main(["--help"]);
      expect(code).toBe(0);
    } finally {
      stderr.restore();
      stdout.restore();
    }
  });

  itEffect("--help on 'run' subcommand exits cleanly", function* () {
    // @effect/cli writes help to its internal Terminal layer, not to
    // process.stdout/stderr, so we only assert the exit code here. The
    // shape of the help text is verified manually via `node dist/bin.js
    // run --help` and is asserted by @effect/cli's own tests upstream.
    const stderr = captureStream(process.stderr);
    const stdout = captureStream(process.stdout);
    try {
      const code = yield* main(["run", "--help"]);
      expect(code).toBe(0);
    } finally {
      stderr.restore();
      stdout.restore();
    }
  });
});

tests/runtime.test.ts.source:
// Real-process tests for SubprocessRuntime. The DockerRuntime tests that
// previously lived here were mocked-execSync string-assembly tests — they
// asserted that we passed the right shell text to a fake docker binary,
// which doesn't tell us anything about whether real Docker accepts the
// command. They were deleted alongside a follow-up plan to (1) replace
// runtime.ts's manual `execSync("docker ...")` driving with dockerode and
// (2) cover Docker behavior with a real-Docker integration suite under
// tests/integration/. Until that ships, runtime.ts's Docker paths are
// covered only by the type system.

import { describe, expect } from "vitest";
import { Effect } from "effect";
import { existsSync } from "node:fs";
import { SubprocessRuntime } from "../src/runner/index.js";
import { AgentId, ProjectId, ScenarioId } from "../src/core/types.js";
import { itEffect, expectLeft } from "./support/effect.js";

describe("SubprocessRuntime", () => {
  itEffect(
    "rejects with BinaryNotFound when bin path does not exist",
    function* () {
      const runtime = new SubprocessRuntime({ bin: "/path/that/definitely/does/not/exist/cc-judge-test" });
      const agent = {
        id: AgentId("subproc-missing-bin"),
        name: "Subproc Missing Bin",
        artifact: {
          _tag: "DockerImageArtifact" as const,
          image: "n/a",
        },
        promptInputs: {},
      };
      const plan = {
        project: ProjectId("cc-judge"),
        scenarioId: ScenarioId("subproc-missing-bin"),
        name: "subproc-missing-bin",
        description: "verify BinaryNotFound when bin path missing",
        agents: [agent] as const,
        requirements: {
          expectedBehavior: "fails with BinaryNotFound",
          validationChecks: ["BinaryNotFound cause"],
        },
      };

      const result = yield* Effect.either(runtime.prepare(agent, plan));
      const error = expectLeft(result);
      expect(error.cause._tag).toBe("BinaryNotFound");
    },
  );

  itEffect(
    "creates and reaps the workspace tmpdir on a successful prepare/stop cycle",
    function* () {
      // /bin/echo is guaranteed to exist on POSIX CI.
      const runtime = new SubprocessRuntime({ bin: "/bin/echo" });
      const scenarioPrefix = `subproc-success-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
      const agent = {
        id: AgentId("subproc-success"),
        name: "Subproc Success",
        artifact: {
          _tag: "DockerImageArtifact" as const,
          image: "n/a",
        },
        promptInputs: {},
      };
      const plan = {
        project: ProjectId("cc-judge"),
        scenarioId: ScenarioId(scenarioPrefix),
        name: "subproc-success",
        description: "happy path: workspace created and removed",
        agents: [agent] as const,
        requirements: {
          expectedBehavior: "workspace lifecycle clean",
          validationChecks: ["created then removed"],
        },
      };

      const handle = yield* runtime.prepare(agent, plan);
      expect(existsSync(handle.workspaceDir)).toBe(true);
      yield* runtime.stop(handle);
      expect(existsSync(handle.workspaceDir)).toBe(false);
    },
  );
});

tests/bundle-pipeline.test.ts.source:
import { mkdtempSync } from "node:fs";
import * as os from "node:os";
import * as path from "node:path";
import { describe, expect } from "vitest";
import { Effect } from "effect";
import { scoreBundles } from "../src/app/pipeline.js";
import type { JudgeBackend } from "../src/judge/index.js";
import type { JudgeResult } from "../src/core/schema.js";
import { AgentId, ProjectId, RunId, ScenarioId, type JudgmentBundle } from "../src/core/types.js";
import { itEffect } from "./support/effect.js";

const stubJudge: JudgeBackend = {
  name: "bundle-judge",
  judge() {
    const result: JudgeResult = {
      pass: true,
      reason: "bundle pass",
      issues: [],
      overallSeverity: null,
      retryCount: 0,
    };
    return Effect.succeed(result);
  },
};

function makeBundle(): JudgmentBundle {
  return {
    runId: RunId("bundle-run-1"),
    project: ProjectId("cc-judge"),
    scenarioId: ScenarioId("bundle-scenario"),
    name: "bundle",
    description: "normalized bundle",
    requirements: {
      expectedBehavior: "judge the bundle",
      validationChecks: ["bundle reaches the judge"],
    },
    agents: [{ id: "agent-1", name: "Agent One" }],
    events: [
      {
        type: "message",
        from: "Agent One",
        channel: "response",
        text: "done",
        ts: 1_744_998_100_000,
      },
    ],
    outcomes: [
      {
        agentId: AgentId("agent-1"),
        status: "completed",
        endedAt: "2026-04-19T00:01:40.000Z",
      },
    ],
    metadata: {
      modelName: "bundle-model",
    },
  };
}

describe("scoreBundles", () => {
  itEffect("scores normalized bundles without a runner", function* () {
    const resultsDir = mkdtempSync(path.join(os.tmpdir(), "cc-judge-bundle-"));
    const report = yield* scoreBundles([makeBundle()], {
      judge: stubJudge,
      resultsDir,
    });

    expect(report.summary.total).toBe(1);
    expect(report.summary.passed).toBe(1);
    expect(report.runs[0]?.source).toBe("bundle");
    expect(report.runs[0]?.modelName).toBe("bundle-model");
  });
});

tests/bundle-codec.test.ts.source:
import { describe, expect } from "vitest";
import { Effect } from "effect";
import { bundleAutoCodec } from "../src/emit/bundle-codec.js";
import { itEffect, EITHER_LEFT } from "./support/effect.js";

describe("bundleAutoCodec", () => {
  itEffect("decodes a normalized YAML bundle", function* () {
    const payload = [
      "runId: bundle-run-1",
      "project: cc-judge",
      "scenarioId: bundle-scenario",
      "name: bundle",
      "description: normalized bundle",
      "requirements:",
      "  expectedBehavior: judge the bundle",
      "  validationChecks:",
      "    - bundle reaches the judge",
      "agents:",
      "  - id: agent-1",
      "    name: Agent One",
      "outcomes:",
      "  - agentId: agent-1",
      "    status: completed",
      "    endedAt: 2026-04-19T00:01:40.000Z",
    ].join("\n");

    const bundle = yield* bundleAutoCodec.decode(payload, "mem://bundle.yaml");

    expect(bundle.runId).toBe("bundle-run-1");
    expect(bundle.project).toBe("cc-judge");
    expect(bundle.outcomes[0]?.agentId).toBe("agent-1");
  });

  itEffect("rejects malformed bundles", function* () {
    const payload = JSON.stringify({
      runId: "bundle-run-1",
      project: "cc-judge",
      scenarioId: "bundle-scenario",
      name: "bundle",
      description: "missing outcomes",
      requirements: {
        expectedBehavior: "judge the bundle",
        validationChecks: ["bundle reaches the judge"],
      },
      agents: [{ id: "agent-1", name: "Agent One" }],
    });

    const result = yield* Effect.either(bundleAutoCodec.decode(payload, "mem://broken.json"));

    expect(result._tag).toBe(EITHER_LEFT);
  });
});
